mapper.update:
UPDATE NMCP_MSTORE_CAN_TRG
SET RVISN_DTTM = SYSDATE
   ,PROC_TRG_YN = 'N'
   ,PROC_YN = 'Y'
	 ,PROC_HIST_SEQ = NULL

	,RESULT_CODE = #{resultCode}


	,MESSAGE = #{message}


	,MSTORE_USER_STAT = #{sreTpCd}

WHERE CAN_TRG_SEQ = #{canTrgSeq}

mapper.insert:

	SELECT (TO_CHAR(SYSDATE,'YYYYMMDD')||TRIM(TO_CHAR(SQ_MSTORE_PROC_HIST.NEXTVAL, '0000'))) AS histSeq FROM DUAL

INSERT INTO NMCP_MSTORE_PROC_HIST (
		HIST_SEQ
   ,TOTAL_CNT
   ,RESULT_CODE
   ,MESSAGE

   ,RESULT


	 ,RESULT_DTL

   ,PROC_DIV_STAT
) VALUES (
	  #{histSeq}
   ,#{totalCnt}
   ,#{resultCode}
   ,#{message}

	 ,#{result}


   ,#{resultDtl}

   ,#{procDivStat}
)

mapper.select:
SELECT NVL(CONTENT_SEQ, 0)
FROM (
    SELECT CONTENT_SEQ
    FROM NMCP_MSTORE_CONTENT
    WHERE JSON_HASH = #{jsonHash}
    AND DEVC_TP_CD = #{devcTpCd}
    ORDER BY CONTENT_SEQ
)
WHERE ROWNUM = 1

mapper.update:

    SELECT SQ_MSTORE_CONTENT.NEXTVAL FROM DUAL

INSERT INTO NMCP_MSTORE_CONTENT (
    CONTENT_SEQ
    , CRET_DAY
    , DEVC_TP_CD
    , STATUS
    , FAIL_MESSAGE
    , JSON_HASH
    , CRET_ID
    , CRET_DT
) VALUES (
    #{contentSeq}
    , TO_CHAR(SYSDATE, 'YYYYMMDD')
    , #{devcTpCd}
    , #{status}
    , #{failMessage}
    , #{jsonHash}
    , #{userId}
    , SYSDATE
)

mapper.insert:
INSERT INTO NMCP_MSTORE_CONTENT_ITEM (
    ITEM_SEQ
    , CONTENT_SEQ
    , ITEM_TYPE
    , NAME
    , URL
    , IMG_URL_PC
    , IMG_URL_MO
    , ORIGINAL_PRICE
    , DISCOUNT_PRICE
    , CRET_ID
    , CRET_DT
) VALUES (
    SQ_MSTORE_CONTENT_ITEM.NEXTVAL
    , #{contentSeq}
    , #{itemType}
    , #{name}
    , #{url}
    , #{imgUrlPc}
    , #{imgUrlMo}
    , #{originalPrice}
    , #{discountPrice}
    , #{userId}
    , SYSDATE
)
